  return {
    ...payload,
    players,
    pendingPlayers,
    pendingPlayerIds,
    you,
    board,
  };
};

async function api(path, init = {}) {
  const headers = new Headers(init.headers || {});
  if (init.body && !headers.has('Content-Type')) {
    headers.set('Content-Type', 'application/json');
  }
  const response = await fetch(path, {
    ...init,
    credentials: 'include',
    headers,
  });
  const json = await response.json().catch(() => ({}));
  if (!response.ok || json?.ok === false) {
    throw new Error(json?.error || `Error ${response.status}`);
  }
  return json;
}

function useWs(enabled) {
  const [state, setState] = useState(null);
  const [connected, setConnected] = useState(false);
  const [serverError, setServerError] = useState('');
  const socketRef = useRef(null);

  useEffect(() => {
    if (!enabled) {
      setConnected(false);
      setState(null);
      setServerError('');
      socketRef.current?.close();
      socketRef.current = null;
      return undefined;
    }

    let disposed = false;
    let retry = 0;
    let reconnectTimer = null;

    const connect = () => {
      if (disposed) return;
      const ws = new WebSocket(WS_URL);
      socketRef.current = ws;

      ws.onopen = () => {
        retry = 0;
        setConnected(true);
      };

      ws.onmessage = (e) => {
        let data;
        try {
          data = JSON.parse(e.data);
        } catch {
          return;
        }
        if (data.type === 'state') {
          setState(sanitizeStatePayload(data));
          setServerError('');
        }
        if (data.type === 'error') {
          setServerError(data.message || 'Error de comunicación con el servidor.');
        }
        if (data.type === 'ended') {
          setState(null);
          alert('La partida ha sido eliminada.');
        }
      };

      ws.onclose = () => {
        setConnected(false);
        setState(null);
        if (disposed) return;
        const waitMs = Math.min(5000, 500 * (2 ** retry));
        retry += 1;
        reconnectTimer = window.setTimeout(connect, waitMs);
      };
    };

    connect();

    return () => {
      disposed = true;
      setConnected(false);
      setServerError('');
      if (reconnectTimer) {
        window.clearTimeout(reconnectTimer);
      }
      socketRef.current?.close();
      socketRef.current = null;
    };
  }, [enabled]);

  const send = useCallback((payload) => {
    const ws = socketRef.current;
    if (ws?.readyState === WebSocket.OPEN) {
      ws.send(JSON.stringify(payload));
    }
  }, []);

  return { state, setState, send, connected, serverError, setServerError };
}

