      gameOver: true,
      winnerIds: room.winnerIds || room.summary.winnerIds || [],
      pointLimit: room.pointLimit || DEFAULT_POINT_LIMIT,
    };
  }

  if (room.phase === 'lobby') {
    state.canStart = room.players.size >= MIN_PLAYERS;
  }

  return state;
}

